  `level` enum('administrator','instansi','pemegang') CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL DEFAULT 'instansi',
  `instansi` varchar(50) CHARACTER SET utf8 COLLATE utf8_unicode_ci NOT NULL,
